2866 bool InstCombinerImpl::SimplifyDemandedFPClass(Instruction *I, unsigned OpNo,
2867                                                FPClassTest DemandedMask,
2868                                                KnownFPClass &Known,
2869                                                unsigned Depth) {
2870   Use &U = I->getOperandUse(OpNo);
2871   Value *V = U.get();
2872   Type *VTy = V->getType();
2873 
2874   if (DemandedMask == fcNone) {
2875     if (isa<UndefValue>(V))
2876       return false;
2877     replaceUse(U, PoisonValue::get(VTy));
2878     return true;
2879   }
2880 
2881   // Handle constant
2882   Instruction *VInst = dyn_cast<Instruction>(V);
2883   if (!VInst) {
2884     // Handle constants and arguments
2885     Known = computeKnownFPClass(V, fcAllFlags, I, Depth);
2886 
2887     FPClassTest ValidResults = DemandedMask & Known.KnownFPClasses;
2888     if (ValidResults == fcNone) {
2889       if (isa<UndefValue>(V))
2890         return false;
2891       replaceUse(U, PoisonValue::get(VTy));
2892       return true;
2893     }
2894 
2895     // Do not try to replace values which are already constants (unless we are
2896     // folding to poison). Doing so could promote poison elements to non-poison
2897     // constants.
2898     if (isa<Constant>(V))
2899       return false;
2900 
2901     Value *FoldedToConst = getFPClassConstant(VTy, ValidResults);
2902     if (!FoldedToConst || FoldedToConst == V)
2903       return false;
2904 
2905     replaceUse(U, FoldedToConst);
2906     return true;
2907   }
2908 
2909   if (Depth == MaxAnalysisRecursionDepth)
2910     return false;
2911 
2912   Value *NewVal;
2913 
2914   if (VInst->hasOneUse()) {
2915     // If the instruction has one use, we can directly simplify it.
2916     NewVal = SimplifyDemandedUseFPClass(VInst, DemandedMask, Known, I, Depth);
2917   } else {
2918     // If there are multiple uses of this instruction, then we can simplify
2919     // VInst to some other value, but not modify the instruction.
2920     NewVal = SimplifyMultipleUseDemandedFPClass(VInst, DemandedMask, Known, I,
2921                                                 Depth);
2922   }
2923 
2924   if (!NewVal)
2925     return false;
2926   if (Instruction *OpInst = dyn_cast<Instruction>(U))
2927     salvageDebugInfo(*OpInst);
2928 
2929   replaceUse(U, NewVal);
2930   return true;
2931 }
